// Normalización y clasificación
const input = items[0].json;
const body = input.body || input;
const message = body.studentMessage || '';

// Normalizar para cache
const normalized = message.toLowerCase().trim().replace(/\s+/g, ' ').replace(/[^\w\s]/g, '');

// Hash simple (FNV-1a)
function simpleHash(str) {
  let hash = 2166136261;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash += (hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24);
  }
  return (hash >>> 0).toString(16);
}

const questionHash = simpleHash(normalized);

// Análisis de complejidad ESPECÍFICO para matemáticas
const wordCount = message.split(/\s+/).length;
const hasComplexMath = /derivad|integr|matriz|vector|ecuación\s+diferencial|límite|teorema/i.test(message);
const hasAdvancedOperations = /\^|√|∫|∑|lim|sen|cos|tan|log/i.test(message);
const difficulty = body.difficultyLevel || 'intermedio';

// Matemático Guía: usa local LLM para aritmética básica y álgebra simple
const isEasyQuestion = (
  wordCount < 25 && 
  difficulty === 'basico' && 
  !hasComplexMath &&
  !hasAdvancedOperations
) || body.forceLocalLLM === true;

return items.map(item => ({
  json: {
    ...body,
    agentKey: 'matematico_guia', // Forzar agentKey
    questionHash,
    normalized,
    isEasyQuestion,
    complexity: { 
      wordCount, 
      hasComplexMath, 
      hasAdvancedOperations 
    }
  }
}));

const data = items[0].json;
const subject = data.subject || 'matemáticas';
const difficulty = data.difficultyLevel || 'intermedio';
const gradeLevel = data.gradeLevel || 'secundaria';
const history = (data.conversationHistory || []).slice(-6);
const historyText = history.map(m => `${m.role === 'user' ? 'Estudiante' : 'Tutor'}: ${m.content}`).join('\n');

// Personalización basada en perfil del estudiante
let adaptations = '';

if (data.studentProfile?.learningStyle === 'visual') {
  adaptations += '- Usá diagramas, gráficos, representaciones visuales.\n';
  adaptations += '- Dibujá ejemplos: "Imaginá que tenés..."\n';
}

if (data.studentProfile?.learningStyle === 'kinesthetic') {
  adaptations += '- Usá objetos concretos: "Si tenés 5 canicas..."\n';
  adaptations += '- Ejemplos físicos y manipulables.\n';
}

if (data.studentProfile?.strugglingAreas?.length) {
  adaptations += `- Áreas difíciles: ${data.studentProfile.strugglingAreas.join(', ')}. Simplificá más en estos temas.\n`;
}

// Adaptación por nivel de dificultad
let difficultyGuidance = '';
if (difficulty === 'basico') {
  difficultyGuidance = '- Usá pasos MUY pequeños\n- Validá cada mini-paso\n- Ejemplos concretos y cotidianos\n';
} else if (difficulty === 'avanzado') {
  difficultyGuidance = '- Desafíos conceptuales\n- Conexiones abstractas\n- Fomenta exploración independiente\n';
}

// System prompt COMPLETO para Matemático Guía
const systemPrompt = `IDENTIDAD Y ROL:
Vos sois "Matemático Guía", tutor experto en matemáticas para estudiantes de Honduras y Centroamérica. Tu objetivo es guiar razonamiento matemático, JAMÁS dar respuestas directas.

PRINCIPIOS FUNDAMENTALES:
1. JAMÁS proporciones la respuesta final o solución completa
2. Hacé preguntas estratégicas que guíen al estudiante: "¿Qué observás?", "¿Cuál es el primer paso?"
3. Usá ejemplos de vida hondureña: mercados, construcción, agricultura, distancias
4. Celebrá el esfuerzo y razonamiento, no solo respuestas correctas
5. Lenguaje conversacional con modismos hondureños ("mirá", "fijate", "pues")

ESTRUCTURA DE RESPUESTAS:
1. Entendé qué intenta el estudiante
2. Identificá dónde está la confusión
3. Hacé UNA pregunta que lo encamine al siguiente paso
4. Si sigue atascado después de 2-3 intentos, dá un hint (NUNCA la respuesta)
5. Guíalo a verificar su razonamiento

CUANDO EL ESTUDIANTE ESTÉ PERDIDO:
- Dividí el problema en partes MÁS pequeñas
- Preguntá: "¿Cuál fue el primer paso?"
- Recordá conceptos previos: "¿Recordás cuando vimos...?"
- Usá diagramas o ejemplos concretos
- NUNCA des un paso sin que lo entiendan primero

ADAPTACIONES ESPECÍFICAS:
${adaptations}

GUÍA POR NIVEL:
${difficultyGuidance}

CONTEXTO ACTUAL:
- Tema: ${subject}
- Nivel dificultad: ${difficulty}
- Grado: ${gradeLevel}

ÚLTIMOS INTERCAMBIOS:
${historyText || 'Inicio de conversación nueva'}

IMPORTANTE:
- Respondé en español Honduras
- Tono educativo, paciente, motivador
- Máximo 3-4 oraciones por respuesta
- Terminá SIEMPRE con una pregunta guía

PREGUNTA ACTUAL DEL ESTUDIANTE:`;

return items.map(item => ({
  json: {
    ...data,
    systemPrompt,
    userMessage: data.studentMessage
  }
}));

const data = items[0].json;
const llmResponse = data.choices?.[0]?.message?.content || '';
const tokensUsed = data.usage?.total_tokens || 0;
const modelUsed = data.model || 'unknown';

const isLocal = modelUsed.includes('qwen') || modelUsed.includes('local');

// Response específica para Matemático Guía
const response = {
  agent: 'matematico_guia',
  message: llmResponse,
  metadata: {
    modelUsed: isLocal ? 'qwen2.5-14b-local' : 'gpt-4o-mini',
    tokensUsed,
    difficulty: data.difficultyLevel || 'intermedio',
    subject: data.subject || 'matemáticas',
    cached: false,
    complexity: data.complexity,
    timestamp: new Date().toISOString()
  }
};

return items.map(item => ({
  json: {
    ...data,
    response
  }
}));
